Text.text:
Data: {dados>/DataCriacao} → {
                path: 'dados>/DataCriacao',
                type: 'sap.ui.model.type.DateTime',
                formatOptions: {
                    UTC: false,
                    pattern: 'dd/MM/yyyy HH:mm:ss'
                }
            }

{
                parts: ['dados>/Preco', 'dados>/Moeda'],
                type: 'sap.ui.model.type.Currency',
                formatOptions: {
                    groupingEnabled: true,
                    groupingSeparator: '.',
                    decimalSeparator: ',',
                    decimals: 2,
                    showMeasure: false
                }
            }
